"use strict";parserFactory.register("shinsori.com",()=>new ShinsoriParser);class ShinsoriParser extends Parser{constructor(){super()}getChapterUrls(e,t){return this.getChapterUrlsFromMultipleTocPages(e,ShinsoriParser.extractPartialChapterList,ShinsoriParser.getUrlsOfTocPages,t)}static getUrlsOfTocPages(e){return[...e.querySelectorAll("ul.lcp_paginator a:not(.lcp_nextlink)")].map(e=>e.href)}static extractPartialChapterList(e){let t=[...e.querySelectorAll("ul.lcp_catlist")];return 0===t.length?[]:util.hyperlinksToChapterList(t[t.length-1])}findContent(e){return e.querySelector("div.entry-content")}extractTitleImpl(e){return e.querySelector("h2.section-title")}extractAuthor(e){let t=util.getElement(e,"strong",e=>"Author:"===e.textContent);return null===t?super.extractAuthor(e):t.nextSibling.textContent}removeUnwantedElementsFromContentElement(e){util.removeElements(e.querySelectorAll("div.stream-item-below-post-content, div.post-bottom-meta")),super.removeUnwantedElementsFromContentElement(e)}findChapterTitle(e){let t=e.querySelector("div.entry-header");if(null!=t){let e=t.querySelector("h5");return null!=e&&e.remove(),t}return e.querySelector("h1")}findParentNodeOfChapterLinkToRemoveAt(e){return util.moveIfParent(e,"p")}findCoverImageUrl(e){return util.getFirstImgSrc(e,"li.post-item")}getInformationEpubItemChildNodes(e){return[...e.querySelectorAll("div.block-custom-content, div.first-half-box")]}cleanInformationNode(e){util.removeChildElementsMatchingSelector(e,"a")}}